import React, { useState, useEffect, useRef } from "react";
import axios from "axios";
import Cookies from "js-cookie";
import { useNavigate } from "react-router-dom";
import { Modal } from "bootstrap";
import { toast } from "react-toastify";
import Toast from "../components/Toast";
import dayjs from "dayjs";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Tooltip,
  Legend,
} from "chart.js";
import { Bar } from "react-chartjs-2";

ChartJS.register(CategoryScale, LinearScale, BarElement, Tooltip, Legend);

const API_BASE_URL =
  process.env.REACT_APP_API_BASE_URL || "http://localhost:5000/api";

function Dashboard() {
  const [users, setUsers] = useState([]);
  const [payments, setPayments] = useState([]);
  const [supports, setSupports] = useState([]);
  const [loading, setLoading] = useState(false);

  const currentYear = new Date().getFullYear();
  const [paymentsYear, setPaymentsYear] = useState(currentYear);
  const [leadYear, setLeadYear] = useState(currentYear);

  const navigate = useNavigate();

  /* ================= FETCH ALL DATA ================= */
  function fetchDashboardData() {
    setLoading(true);
    const token = Cookies.get("adminToken");

    if (!token) {
      navigate("/");
      return;
    }

    Promise.all([
      axios.get(API_BASE_URL + "/users", {
        headers: { Authorization: "Bearer " + token },
      }),
      axios.get(API_BASE_URL + "/payments", {
        headers: { Authorization: "Bearer " + token },
      }),
      axios.get(API_BASE_URL + "/supports", {
        headers: { Authorization: "Bearer " + token },
      }),
    ])
      .then(([usersRes, paymentsRes, supportsRes]) => {
        setUsers(usersRes.data.data || []);
        setPayments(paymentsRes.data.data || []);
        setSupports(supportsRes.data.data || []);
      })
      .catch((err) =>
        toast.error(err.response?.data?.error || "Failed to fetch data")
      )
      .finally(() => setLoading(false));
  }

  useEffect(() => {
    fetchDashboardData();
  }, []);

  /* ================= SUMMARY ================= */
  const totalUsers = users.length;
  const totalClients = users.filter((u) => u.isConverted === 1).length;
  const totalRevenue = payments.reduce(
    (sum, p) => sum + Number(p.paidAmount || 0),
    0
  );
  const totalSupportTickets = supports.length;

  /* ================= LEADS DATA ================= */
  const groupedLeads = {};
  users.forEach((u) => {
    const date = dayjs(u.createdAt);
    const year = date.year();
    const month = date.month() + 1;
    if (!groupedLeads[year]) groupedLeads[year] = {};
    if (!groupedLeads[year][month])
      groupedLeads[year][month] = { leads: 0, approved: 0, duplicate: 0 };

    groupedLeads[year][month].leads += 1;
    if (u.status === "approved") groupedLeads[year][month].approved += 1;
    if (u.status === "duplicate") groupedLeads[year][month].duplicate += 1;
  });

  const leadYearData = groupedLeads[leadYear] || {};
  const leadMonths = Object.keys(leadYearData);
  const leadChartData = {
    labels: leadMonths.map((m) => dayjs(`${leadYear}-${m}-01`).format("MMM")),
    datasets: [
      {
        label: "Total Leads",
        data: leadMonths.map((m) => leadYearData[m].leads),
        backgroundColor: "#0d6efd65",
        borderRadius: 8,
      },
      {
        label: "Approved",
        data: leadMonths.map((m) => leadYearData[m].approved),
        backgroundColor: "#19875475",
        borderRadius: 8,
      },
      {
        label: "Duplicate",
        data: leadMonths.map((m) => leadYearData[m].duplicate),
        backgroundColor: "#dc354575",
        borderRadius: 8,
      },
    ],
  };

  /* ================= PAYMENTS DATA ================= */
  const groupedPayments = {};
  payments.forEach((p) => {
    const date = dayjs(p.paymentDate);
    const year = date.year();
    const month = date.month() + 1;
    if (!groupedPayments[year]) groupedPayments[year] = {};
    if (!groupedPayments[year][month])
      groupedPayments[year][month] = { clients: 0, payments: 0 };

    groupedPayments[year][month].clients += 1;
    groupedPayments[year][month].payments += Number(p.paidAmount || 0);
  });

  const paymentsYearDataObj = groupedPayments[paymentsYear] || {};
  const paymentMonths = Object.keys(paymentsYearDataObj);
  const paymentsChartData = {
    labels: paymentMonths.map((m) =>
      dayjs(`${paymentsYear}-${m}-01`).format("MMM")
    ),
    datasets: [
      {
        label: "Clients Converted",
        data: paymentMonths.map((m) => paymentsYearDataObj[m].clients || 0),
        backgroundColor: "#0d6efd65",
        yAxisID: "yClients",
        borderRadius: 8,
      },
      {
        label: "Payments (₹)",
        data: paymentMonths.map((m) => paymentsYearDataObj[m].payments || 0),
        backgroundColor: "#19875475",
        yAxisID: "yAmount",
        borderRadius: 8,
      },
      {
        label: "Commission (10%)",
        data: paymentMonths.map(
          (m) => Math.round((paymentsYearDataObj[m].payments || 0) * 0.1)
        ),
        backgroundColor: "#ffc10775",
        yAxisID: "yAmount",
        borderRadius: 8,
      },
    ],
  };

  const paymentsChartOptions = {
    responsive: true,
    plugins: { legend: { position: "top" } },
    scales: {
      x: { grid: { display: false } },
      yClients: { type: "linear", position: "left", beginAtZero: true },
      yAmount: { type: "linear", position: "right", beginAtZero: true, grid: { drawOnChartArea: false } },
    },
  };

  if (loading)
    return <div className="text-center p-5">Loading Dashboard...</div>;

  return (
    <div className="container py-3">
      <Toast />

      {/* Summary Cards */}
      <div className="row g-3 mb-3">
        <Card title="Total Users" value={totalUsers} />
        <Card title="Total Clients" value={totalClients} />
        <Card title="Total Revenue" value={`₹${totalRevenue.toLocaleString("en-IN")}`} />
        <Card title="Support Tickets" value={totalSupportTickets} />
      </div>

      {/* Charts */}
      <div className="row g-3">
        <div className="col-lg-6">
          <div className="border rounded p-3 bg-body">
            <h6 className="fw-bold mb-3">Leads ({leadYear})</h6>
            <Bar data={leadChartData} />
          </div>
        </div>
        <div className="col-lg-6">
          <div className="border rounded p-3 bg-body">
            <h6 className="fw-bold mb-3">Payments ({paymentsYear})</h6>
            <Bar data={paymentsChartData} options={paymentsChartOptions} />
          </div>
        </div>
      </div>
    </div>
  );
}

const Card = ({ title, value }) => (
  <div className="col-md-3 col-6">
    <div className="p-3 rounded bg-body border-start border-5 border-primary border-opacity-25">
      <small>{title}</small>
      <h5>{value}</h5>
    </div>
  </div>
);

export default Dashboard;
